function stoneGameII(piles) {
    let n = piles.length;
    let memo = new Array(n).fill(0).map(() => new Array(n + 1).fill(0));

    for (let i = n - 2 ; i >= 0; --i) {
        piles[i] += piles[i + 1];
    }

    function search(idx, M) {
        if (idx + 2 * M >= n) {
            return piles[idx];
        }

        if (memo[idx][M] > 0) {
            return memo[idx][M];
        }

        memo[idx][M] = 0;

        for (let x = 1; x <= 2 * M; ++x) {
            memo[idx][M] = Math.max(memo[idx][M], piles[idx] - search(idx + x, Math.max(M, x)));
        }

        return memo[idx][M];
    }

    return search(0, 1);
}
