public int stoneGameII(int[] piles) {
    int n = piles.length;
    int[][] memo = new int[n][n + 1];

    for (int i = n - 2 ; i >= 0; --i) {
        piles[i] += piles[i + 1];
    }

    return search(piles, 0, 1, memo);
}

private int search(int[] piles, int idx, int M, int[][] memo) {
    int n = piles.length;

    if (idx + 2 * M >= n) {
        return piles[idx];
    }

    if (memo[idx][M] > 0) {
        return memo[idx][M];
